     1→import React, { useState, useRef, useMemo, useEffect } from 'react';
     2→import {
     3→  DndContext,
     4→  DragOverlay,
     5→  PointerSensor,
     6→  TouchSensor,
     7→  useSensor,
     8→  useSensors,
     9→  closestCorners,
    10→  type DragEndEvent,
    11→  type DragStartEvent,
    12→} from '@dnd-kit/core';
    13→import { Widget } from '../components/Widget';
    14→import { KeyboardShortcutsHelp } from '../components/KeyboardShortcutsHelp';
    15→import { ConfirmDialog } from '../components/ConfirmDialog';
    16→import { Toast } from '../components/Toast';
    17→import { useKanbanStore } from '../stores/useKanbanStore';
    18→import { useKanbanKeyboard } from '../hooks/useKanbanKeyboard';
    19→import { KanbanColumn } from './Kanban/KanbanColumn';
    20→import { KanbanCard } from './Kanban/KanbanCard';
    21→import { ColumnManager } from './Kanban/ColumnManager';
    22→import { CardDetailPanel } from './Kanban/CardDetailPanel';
    23→import { ListView } from './Kanban/ListView';
    24→import { ArchivedView } from './Kanban/ArchivedView';
    25→import { QuickAddModal } from './Kanban/QuickAddModal';
    26→import type { Task, TaskStatus } from '../types';
    27→
    28→/**
    29→ * Kanban Board Widget - React Version with Drag & Drop
    30→ *
    31→ * Features:
    32→ * - Three-column board (To Do, In Progress, Done)
    33→ * - Drag and drop tasks between columns
    34→ * - Task CRUD operations
    35→ * - Priority and due date tracking
    36→ * - Syncs with Calendar widget
    37→ * - Keyboard shortcuts for navigation and actions
    38→ */
    39→export const Kanban: React.FC = () => {
    40→  const { tasks, columns, moveTask, deleteTask, updateTask, undo, undoHistory, autoArchiveCompletedTasks, visibleColumns = 5, setVisibleColumns } = useKanbanStore();
    41→  const [activeTask, setActiveTask] = useState<Task | null>(null);
    42→  const [showColumnManager, setShowColumnManager] = useState(false);
    43→  const [showArchivedView, setShowArchivedView] = useState(false);
    44→  const [showQuickAdd, setShowQuickAdd] = useState(false);
    45→  const [toast, setToast] = useState<{ message: string; showUndo: boolean } | null>(null);
    46→  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
    47→  const [selectedTab, setSelectedTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity'>('subtasks');
    48→
    49→  // View mode state with persistence
    50→  const [viewMode, setViewMode] = useState<'board' | 'list'>(() => {
    51→    const saved = localStorage.getItem('kanban-view-mode');
    52→    return (saved as 'board' | 'list') || 'board';
    53→  });
    54→
    55→  // Filter state
    56→  const [searchQuery, setSearchQuery] = useState('');
    57→  const [selectedPriorities, setSelectedPriorities] = useState<Set<string>>(new Set());
    58→  const [selectedTags, setSelectedTags] = useState<Set<string>>(new Set());
    59→  const [showFilters, setShowFilters] = useState(false);
    60→
    61→  // Refs for columns to trigger their add forms
    62→  const columnRefs = useRef<Record<string, { triggerAdd: () => void }>>({});
    63→  const cardRefs = useRef<Record<string, { triggerEdit: () => void }>>({});
    64→
    65→  // Configure sensors for drag-drop (mouse + touch)
    66→  const sensors = useSensors(
    67→    useSensor(PointerSensor, {
    68→      activationConstraint: {
    69→        distance: 8, // 8px movement before drag starts
    70→      },
    71→    }),
    72→    useSensor(TouchSensor, {
    73→      activationConstraint: {
    74→        delay: 250, // 250ms long press
    75→        tolerance: 5, // 5px movement tolerance
    76→      },
    77→    })
    78→  );
    79→
    80→  // Sort columns by order
    81→  const sortedColumns = useMemo(() => {
    82→    return [...columns].sort((a, b) => a.order - b.order);
    83→  }, [columns]);
    84→
    85→  const columnStatuses = sortedColumns.map((col) => col.id);
    86→
    87→  // Get all unique tags from tasks
    88→  const allTags = useMemo(() => {
    89→    const tagSet = new Set<string>();
    90→    tasks.forEach((task) => task.tags.forEach((tag) => tagSet.add(tag)));
    91→    return Array.from(tagSet).sort();
    92→  }, [tasks]);
    93→
    94→  // Filter tasks based on search and filters
    95→  const filteredTasks = useMemo(() => {
    96→    return tasks.filter((task) => {
    97→      // Search filter (title, description, or card number)
    98→      if (searchQuery) {
    99→        const query = searchQuery.toLowerCase();
   100→
   101→        // Phase A: Support searching by card number (e.g., "KAN-1", "1", "kan1")
   102→        const cardNumberStr = task.cardNumber ? `KAN-${task.cardNumber}`.toLowerCase() : '';
   103→        const cardNumberSimple = task.cardNumber?.toString() || '';
   104→
   105→        const matchesSearch =
   106→          task.title.toLowerCase().includes(query) ||
   107→          task.description.toLowerCase().includes(query) ||
   108→          cardNumberStr.includes(query) ||
   109→          cardNumberSimple.includes(query);
   110→
   111→        if (!matchesSearch) return false;
   112→      }
   113→
   114→      // Priority filter
   115→      if (selectedPriorities.size > 0 && !selectedPriorities.has(task.priority)) {
   116→        return false;
   117→      }
   118→
   119→      // Tags filter
   120→      if (selectedTags.size > 0) {
   121→        const hasSelectedTag = task.tags.some((tag) => selectedTags.has(tag));
   122→        if (!hasSelectedTag) return false;
   123→      }
   124→
   125→      return true;
   126→    });
   127→  }, [tasks, searchQuery, selectedPriorities, selectedTags]);
   128→
   129→  // Toggle filter helpers
   130→  const togglePriority = (priority: string) => {
   131→    setSelectedPriorities((prev) => {
   132→      const newSet = new Set(prev);
   133→      if (newSet.has(priority)) {
   134→        newSet.delete(priority);
   135→      } else {
   136→        newSet.add(priority);
   137→      }
   138→      return newSet;
   139→    });
   140→  };
   141→
   142→  const toggleTag = (tag: string) => {
   143→    setSelectedTags((prev) => {
   144→      const newSet = new Set(prev);
   145→      if (newSet.has(tag)) {
   146→        newSet.delete(tag);
   147→      } else {
   148→        newSet.add(tag);
   149→      }
   150→      return newSet;
   151→    });
   152→  };
   153→
   154→  const clearFilters = () => {
   155→    setSearchQuery('');
   156→    setSelectedPriorities(new Set());
   157→    setSelectedTags(new Set());
   158→  };
   159→
   160→  const hasActiveFilters =
   161→    searchQuery || selectedPriorities.size > 0 || selectedTags.size > 0;
   162→
   163→  // Keyboard shortcuts
   164→  const {
   165→    selectedColumn,
   166→    selectedTaskId,
   167→    showHelp,
   168→    closeHelp,
   169→    pendingDeleteTask,
   170→    confirmDelete,
   171→    cancelDelete,
   172→  } = useKanbanKeyboard({
   173→    columns: columnStatuses,
   174→    tasks: filteredTasks, // Use filtered tasks for keyboard navigation
   175→    onAddTask: (status) => {
   176→      // Trigger the add form in the selected column
   177→      columnRefs.current[status]?.triggerAdd();
   178→    },
   179→    onEditTask: (task) => {
   180→      // Trigger edit mode for the selected task
   181→      cardRefs.current[task.id]?.triggerEdit();
   182→    },
   183→    onDeleteTask: (taskId) => {
   184→      deleteTask(taskId);
   185→    },
   186→  });
   187→
   188→  const handleDragStart = (event: DragStartEvent) => {
   189→    const taskId = event.active.id as string;
   190→    const task = tasks.find((t) => t.id === taskId);
   191→    setActiveTask(task || null);
   192→  };
   193→
   194→  const handleDragEnd = (event: DragEndEvent) => {
   195→    const { active, over } = event;
   196→
   197→    setActiveTask(null);
   198→
   199→    if (!over) return;
   200→
   201→    const taskId = active.id as string;
   202→    const newStatus = over.id as TaskStatus;
   203→
   204→    // Move task to new column
   205→    moveTask(taskId, newStatus);
   206→  };
   207→
   208→  // View mode persistence
   209→  useEffect(() => {
   210→    localStorage.setItem('kanban-view-mode', viewMode);
   211→  }, [viewMode]);
   212→
   213→  // Phase A: Auto-archive completed tasks on mount
   214→  useEffect(() => {
   215→    autoArchiveCompletedTasks();
   216→  }, []); // Run once on mount
   217→
   218→  // Phase A: Global keyboard shortcut for Quick Add (Cmd/Ctrl+K)
   219→  useEffect(() => {
   220→    const handleGlobalKeyDown = (e: KeyboardEvent) => {
   221→      // Cmd/Ctrl+K to open Quick Add
   222→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   223→        // Don't trigger if user is typing in an input/textarea
   224→        const target = e.target as HTMLElement;
   225→        if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) {
   226→          return;
   227→        }
   228→
   229→        e.preventDefault();
   230→        setShowQuickAdd(true);
   231→      }
   232→    };
   233→
   234→    window.addEventListener('keydown', handleGlobalKeyDown);
   235→    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
   236→  }, []);
   237→
   238→  // Listen for undo history changes and show toast
   239→  useEffect(() => {
   240→    if (undoHistory.length > 0) {
   241→      const lastEntry = undoHistory[undoHistory.length - 1];
   242→      setToast({
   243→        message: lastEntry.description,
   244→        showUndo: true,
   245→      });
   246→    }
   247→  }, [undoHistory]);
   248→
   249→  const handleUndo = () => {
   250→    undo();
   251→    setToast(null);
   252→  };
   253→
   254→  return (
   255→    <Widget
   256→      id="kanban"
   257→      title="Kanban Board"
   258→      category="Planning"
   259→      draggable={false}
   260→      headerAccessory={
   261→        <div className="flex items-center gap-1">
   262→          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary mr-2">
   263→            Columns:
   264→          </span>
   265→          {[3, 4, 5, 6, 7].map((count) => (
   266→            <button
   267→              key={count}
   268→              onClick={() => setVisibleColumns(count)}
   269→              className={`px-2 py-1 text-xs font-medium rounded transition-colors ${
   270→                visibleColumns === count
   271→                  ? 'bg-accent-blue text-white'
   272→                  : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary hover:bg-neutral-200 dark:hover:bg-neutral-700'
   273→              }`}
   274→              title={`Show ${count} columns at once`}
   275→            >
   276→              {count}
   277→            </button>
   278→          ))}
   279→        </div>
   280→      }
   281→    >
   282→      {/* Filter Bar */}
   283→      <div className="mb-4 space-y-3">
   284→        {/* Search and Filter Toggle */}
   285→        <div className="flex gap-2">
   286→          <input
   287→            type="text"
   288→            value={searchQuery}
   289→            onChange={(e) => setSearchQuery(e.target.value)}
   290→            placeholder="Search tasks (by title, description, or KAN-#)..."
   291→            className="flex-1 px-4 py-2 text-sm border border-neutral-lightGray dark:border-neutral-darkGray rounded-lg bg-white dark:bg-neutral-charcoal text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:outline-none focus:ring-2 focus:ring-accent-primary"
   292→          />
   293→          <button
   294→            onClick={() => setShowColumnManager(true)}
   295→            className="px-4 py-2 text-sm font-medium bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors whitespace-nowrap"
   296→            title="Manage Columns"
   297→          >
   298→            ⚙️ Columns
   299→          </button>
   300→          <button
   301→            onClick={() => setShowArchivedView(true)}
   302→            className="px-4 py-2 text-sm font-medium bg-surface-light-elevated dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary rounded-lg border border-border-light dark:border-border-dark hover:bg-surface-light dark:hover:bg-surface-dark-elevated transition-colors whitespace-nowrap"
   303→            title="View Archived Tasks"
   304→          >
   305→            📦 Archived
   306→          </button>
   307→          {/* View Toggle */}
   308→          <div className="flex rounded-lg overflow-hidden border border-border-light dark:border-border-dark">
   309→            <button
   310→              onClick={() => setViewMode('board')}
   311→              className={`px-3 py-2 text-sm font-medium transition-colors whitespace-nowrap ${
   312→                viewMode === 'board'
   313→                  ? 'bg-accent-blue text-white'
   314→                  : 'bg-white dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-50 dark:hover:bg-neutral-700'
   315→              }`}
   316→              title="Board View"
   317→            >
   318→              📋 Board
   319→            </button>
   320→            <button
   321→              onClick={() => setViewMode('list')}
   322→              className={`px-3 py-2 text-sm font-medium transition-colors whitespace-nowrap border-l border-border-light dark:border-border-dark ${
   323→                viewMode === 'list'
   324→                  ? 'bg-accent-blue text-white'
   325→                  : 'bg-white dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-50 dark:hover:bg-neutral-700'
   326→              }`}
   327→              title="List View"
   328→            >
   329→              📊 List
   330→            </button>
   331→          </div>
   332→          <button
   333→            onClick={() => setShowFilters(!showFilters)}
   334→            className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors whitespace-nowrap ${
   335→              showFilters || hasActiveFilters
   336→                ? 'bg-accent-primary text-white'
   337→                : 'bg-neutral-paleGray dark:bg-neutral-darkGray text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-lightGray dark:hover:bg-neutral-gray'
   338→            }`}
   339→          >
   340→            🔍 Filters {hasActiveFilters && `(${[...selectedPriorities, ...selectedTags].length})`}
   341→          </button>
   342→          {hasActiveFilters && (
   343→            <button
   344→              onClick={clearFilters}
   345→              className="px-4 py-2 text-sm font-medium bg-neutral-gray text-white rounded-lg hover:opacity-80 transition-opacity"
   346→            >
   347→              Clear
   348→            </button>
   349→          )}
   350→        </div>
   351→
   352→        {/* Advanced Filters (collapsible) */}
   353→        {showFilters && (
   354→          <div className="p-4 bg-neutral-paleGray dark:bg-neutral-darkGray rounded-lg space-y-3">
   355→            {/* Priority Filter */}
   356→            <div>
   357→              <label className="block text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2 uppercase tracking-wide">
   358→                Priority
   359→              </label>
   360→              <div className="flex gap-2 flex-wrap">
   361→                {(['low', 'medium', 'high'] as const).map((priority) => (
   362→                  <button
   363→                    key={priority}
   364→                    onClick={() => togglePriority(priority)}
   365→                    className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-all ${
   366→                      selectedPriorities.has(priority)
   367→                        ? 'bg-accent-primary text-white ring-2 ring-accent-primary ring-offset-2 ring-offset-white dark:ring-offset-neutral-darkGray'
   368→                        : 'bg-white dark:bg-neutral-charcoal text-text-light-secondary dark:text-text-dark-secondary border border-neutral-lightGray dark:border-neutral-gray hover:border-accent-primary'
   369→                    }`}
   370→                  >
   371→                    {priority.charAt(0).toUpperCase() + priority.slice(1)}
   372→                  </button>
   373→                ))}
   374→              </div>
   375→            </div>
   376→
   377→            {/* Tags Filter */}
   378→            {allTags.length > 0 && (
   379→              <div>
   380→                <label className="block text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2 uppercase tracking-wide">
   381→                  Tags
   382→                </label>
   383→                <div className="flex gap-2 flex-wrap">
   384→                  {allTags.map((tag) => (
   385→                    <button
   386→                      key={tag}
   387→                      onClick={() => toggleTag(tag)}
   388→                      className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-all ${
