   100→        {...attributes}
   101→        {...listeners}
   102→        className="cursor-grab active:cursor-grabbing text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary"
   103→        aria-label="Drag to reorder"
   104→      >
   105→        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
   106→          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8h16M4 16h16" />
   107→        </svg>
   108→      </button>
   109→
   110→      {/* Color indicator */}
   111→      <div className={`w-4 h-4 rounded-full ${column.color}`}></div>
   112→
   113→      {/* Column info */}
   114→      <div className="flex-1 min-w-0">
   115→        <div className="font-medium text-text-light-primary dark:text-text-dark-primary truncate">
   116→          {column.title}
   117→        </div>
   118→        {column.wipLimit && (
   119→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   120→            WIP Limit: {column.wipLimit}
   121→          </div>
   122→        )}
   123→      </div>
   124→
   125→      {/* Actions */}
   126→      <div className="flex items-center gap-2">
   127→        <button
   128→          onClick={() => onEdit(column)}
   129→          className="p-1.5 text-text-light-secondary hover:text-accent-blue dark:text-text-dark-secondary dark:hover:text-accent-blue transition-colors"
   130→          aria-label="Edit column"
   131→        >
   132→          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
   133→            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
   134→          </svg>
   135→        </button>
   136→        <button
   137→          onClick={() => onDelete(column.id)}
   138→          className="p-1.5 text-text-light-secondary hover:text-status-error dark:text-text-dark-secondary dark:hover:text-status-error transition-colors"
   139→          aria-label="Delete column"
   140→        >
   141→          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
   142→            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
   143→          </svg>
   144→        </button>
   145→      </div>
   146→    </div>
   147→  );
   148→};
   149→
   150→/**
   151→ * ColumnManager Component
   152→ * Modal for managing Kanban columns (add, edit, delete, reorder, templates)
   153→ */
   154→export const ColumnManager: React.FC<ColumnManagerProps> = ({ isOpen, onClose }) => {
   155→  const { columns, addColumn, updateColumn, deleteColumn, reorderColumns, replaceAllColumns } = useKanbanStore();
   156→  const [editingColumn, setEditingColumn] = useState<KanbanColumn | null>(null);
   157→  const [showAddForm, setShowAddForm] = useState(false);
   158→  const [activeId, setActiveId] = useState<string | null>(null);
   159→
   160→  // Confirmation dialog state
   161→  const [pendingDeleteColumn, setPendingDeleteColumn] = useState<KanbanColumn | null>(null);
   162→  const [pendingTemplate, setPendingTemplate] = useState<keyof typeof TEMPLATES | null>(null);
   163→
   164→  // Error state
   165→  const [error, setError] = useState<string | null>(null);
   166→
   167→  // Form state
   168→  const [formData, setFormData] = useState({
   169→    title: '',
   170→    color: 'bg-status-info',
   171→    wipLimit: undefined as number | undefined,
   172→  });
   173→
   174→  // Drag sensors
   175→  const sensors = useSensors(
   176→    useSensor(PointerSensor, {
   177→      activationConstraint: {
   178→        distance: 8,
   179→      },
   180→    })
   181→  );
   182→
   183→  const handleDragStart = (event: DragStartEvent) => {
   184→    setActiveId(event.active.id as string);
   185→  };
   186→
   187→  const handleDragEnd = (event: DragEndEvent) => {
   188→    const { active, over } = event;
   189→    setActiveId(null);
   190→
   191→    if (over && active.id !== over.id) {
   192→      const oldIndex = columns.findIndex((col) => col.id === active.id);
   193→      const newIndex = columns.findIndex((col) => col.id === over.id);
   194→
   195→      const newOrder = [...columns];
   196→      const [moved] = newOrder.splice(oldIndex, 1);
   197→      newOrder.splice(newIndex, 0, moved);
   198→
   199→      reorderColumns(newOrder.map((col) => col.id));
   200→    }
   201→  };
   202→
   203→  const handleEdit = (column: KanbanColumn) => {
   204→    setEditingColumn(column);
   205→    setFormData({
   206→      title: column.title,
   207→      color: column.color,
   208→      wipLimit: column.wipLimit,
   209→    });
   210→    setShowAddForm(true);
   211→  };
   212→
   213→  const handleDelete = (id: string) => {
   214→    if (columns.length <= 1) {
   215→      setError('Cannot delete the last column. You must have at least one column.');
   216→      return;
   217→    }
   218→
   219→    const column = columns.find((col) => col.id === id);
   220→    if (column) {
   221→      setPendingDeleteColumn(column);
   222→    }
   223→  };
   224→
   225→  const confirmDelete = () => {
   226→    if (pendingDeleteColumn) {
   227→      deleteColumn(pendingDeleteColumn.id);
   228→      setPendingDeleteColumn(null);
   229→      setError(null);
   230→    }
   231→  };
   232→
   233→  const cancelDelete = () => {
   234→    setPendingDeleteColumn(null);
   235→  };
   236→
   237→  const handleSubmit = (e: React.FormEvent) => {
   238→    e.preventDefault();
   239→
   240→    if (!formData.title.trim()) return;
   241→
   242→    if (editingColumn) {
   243→      // Update existing column
   244→      updateColumn(editingColumn.id, {
   245→        title: formData.title.trim(),
   246→        color: formData.color,
   247→        wipLimit: formData.wipLimit || undefined,
   248→      });
   249→    } else {
   250→      // Add new column
   251→      addColumn({
   252→        title: formData.title.trim(),
   253→        color: formData.color,
   254→        wipLimit: formData.wipLimit || undefined,
   255→      });
   256→    }
   257→
   258→    // Reset form
   259→    setFormData({ title: '', color: 'bg-status-info', wipLimit: undefined });
   260→    setEditingColumn(null);
   261→    setShowAddForm(false);
   262→  };
   263→
   264→  const handleCancel = () => {
   265→    setFormData({ title: '', color: 'bg-status-info', wipLimit: undefined });
   266→    setEditingColumn(null);
   267→    setShowAddForm(false);
   268→  };
   269→
   270→  const applyTemplate = (templateKey: keyof typeof TEMPLATES) => {
   271→    setPendingTemplate(templateKey);
   272→  };
   273→
   274→  const confirmTemplate = () => {
   275→    if (pendingTemplate) {
   276→      // Use atomic replace to avoid race condition
   277→      replaceAllColumns(TEMPLATES[pendingTemplate]);
   278→
   279→      setPendingTemplate(null);
   280→      setError(null);
   281→    }
   282→  };
   283→
   284→  const cancelTemplate = () => {
   285→    setPendingTemplate(null);
   286→  };
   287→
   288→  const activeColumn = columns.find((col) => col.id === activeId);
   289→
   290→  return (
   291→    <Modal isOpen={isOpen} onClose={onClose} title="Manage Columns" maxWidth="lg">
   292→      <div className="space-y-6">
   293→        {/* Templates */}
   294→        <div>
   295→          <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
   296→            Templates
   297→          </h4>
   298→          <div className="grid grid-cols-3 gap-2">
   299→            <button
   300→              onClick={() => applyTemplate('dev')}
   301→              className="px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg hover:border-accent-blue transition-colors text-text-light-primary dark:text-text-dark-primary"
   302→            >
   303→              Development
   304→            </button>
   305→            <button
   306→              onClick={() => applyTemplate('pm')}
   307→              className="px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg hover:border-accent-blue transition-colors text-text-light-primary dark:text-text-dark-primary"
   308→            >
   309→              Project Management
   310→            </button>
   311→            <button
   312→              onClick={() => applyTemplate('marketing')}
   313→              className="px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg hover:border-accent-blue transition-colors text-text-light-primary dark:text-text-dark-primary"
   314→            >
   315→              Marketing
   316→            </button>
   317→          </div>
   318→        </div>
   319→
   320→        {/* Column List */}
   321→        <div>
   322→          <div className="flex items-center justify-between mb-3">
   323→            <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
   324→              Columns ({columns.length})
   325→            </h4>
   326→            {!showAddForm && (
   327→              <button
   328→                onClick={() => setShowAddForm(true)}
   329→                className="text-sm text-accent-blue hover:text-accent-blue-hover"
   330→              >
   331→                + Add Column
   332→              </button>
   333→            )}
   334→          </div>
   335→
   336→          {/* Add/Edit Form */}
   337→          {showAddForm && (
   338→            <form onSubmit={handleSubmit} className="mb-4 p-4 bg-surface-light dark:bg-surface-dark rounded-lg border-2 border-accent-blue space-y-3">
   339→              <div>
   340→                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   341→                  Column Name
   342→                </label>
   343→                <input
   344→                  type="text"
   345→                  value={formData.title}
   346→                  onChange={(e) => setFormData({ ...formData, title: e.target.value })}
   347→                  placeholder="e.g., In Progress"
   348→                  className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:outline-none"
   349→                  autoFocus
   350→                />
   351→              </div>
   352→
   353→              <div>
   354→                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   355→                  Color
   356→                </label>
   357→                <div className="flex gap-2 flex-wrap">
   358→                  {COLOR_OPTIONS.map((option) => (
   359→                    <button
   360→                      key={option.class}
   361→                      type="button"
   362→                      onClick={() => setFormData({ ...formData, color: option.class })}
   363→                      className={`w-8 h-8 rounded-full ${option.preview} ${
   364→                        formData.color === option.class
   365→                          ? 'ring-2 ring-accent-blue ring-offset-2 ring-offset-surface-light dark:ring-offset-surface-dark'
   366→                          : ''
   367→                      }`}
   368→                      title={option.label}
   369→                    />
   370→                  ))}
   371→                </div>
   372→              </div>
   373→
   374→              <div>
   375→                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   376→                  WIP Limit (Optional)
   377→                </label>
   378→                <input
   379→                  type="number"
   380→                  value={formData.wipLimit || ''}
   381→                  onChange={(e) =>
   382→                    setFormData({
   383→                      ...formData,
   384→                      wipLimit: e.target.value ? parseInt(e.target.value) : undefined,
   385→                    })
   386→                  }
   387→                  placeholder="e.g., 5"
   388→                  min="1"
   389→                  className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:outline-none"
   390→                />
   391→                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   392→                  Maximum number of tasks allowed in this column
   393→                </p>
   394→              </div>
   395→
   396→              <div className="flex gap-2">
   397→                <button
   398→                  type="submit"
   399→                  className="flex-1 px-4 py-2 text-sm bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors"
   400→                >
   401→                  {editingColumn ? 'Update Column' : 'Add Column'}
   402→                </button>
   403→                <button
   404→                  type="button"
   405→                  onClick={handleCancel}
   406→                  className="px-4 py-2 text-sm bg-neutral-600 text-white rounded-lg hover:opacity-80 transition-opacity"
   407→                >
   408→                  Cancel
   409→                </button>
   410→              </div>
   411→            </form>
   412→          )}
   413→
   414→          {/* Sortable Column List */}
   415→          <DndContext
   416→            sensors={sensors}
   417→            collisionDetection={closestCenter}
   418→            onDragStart={handleDragStart}
   419→            onDragEnd={handleDragEnd}
   420→          >
   421→            <SortableContext items={columns.map((col) => col.id)} strategy={verticalListSortingStrategy}>
   422→              <div className="space-y-2">
   423→                {columns.map((column) => (
   424→                  <SortableColumnItem
   425→                    key={column.id}
   426→                    column={column}
   427→                    onEdit={handleEdit}
   428→                    onDelete={handleDelete}
   429→                  />
   430→                ))}
   431→              </div>
   432→            </SortableContext>
   433→
   434→            <DragOverlay>
   435→              {activeColumn && (
   436→                <div className="flex items-center gap-3 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark shadow-lg">
   437→                  <div className={`w-4 h-4 rounded-full ${activeColumn.color}`}></div>
   438→                  <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
   439→                    {activeColumn.title}
   440→                  </div>
   441→                </div>
   442→              )}
   443→            </DragOverlay>
   444→          </DndContext>
   445→        </div>
   446→
   447→        {/* Error Message */}
   448→        {error && (
   449→          <div className="p-3 bg-status-error/10 border border-status-error rounded-lg text-status-error text-sm">
   450→            {error}
   451→          </div>
   452→        )}
   453→
   454→        {/* Help Text */}
   455→        <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary bg-surface-light-elevated dark:bg-surface-dark-elevated p-3 rounded-lg">
   456→          <p className="font-medium mb-1">Tips:</p>
   457→          <ul className="space-y-1 list-disc list-inside">
   458→            <li>Drag columns to reorder them on the board</li>
   459→            <li>Set WIP limits to prevent overload in any column</li>
   460→            <li>Deleting a column moves all tasks to Backlog</li>
   461→            <li>Templates replace all current columns</li>
   462→          </ul>
   463→        </div>
   464→      </div>
   465→
   466→      {/* Delete Confirmation Dialog */}
   467→      {pendingDeleteColumn && (
   468→        <ConfirmDialog
   469→          isOpen={true}
   470→          onClose={cancelDelete}
   471→          onConfirm={confirmDelete}
   472→          title="Delete Column"
   473→          message={`Are you sure you want to delete "${pendingDeleteColumn.title}"? All tasks in this column will be moved to Backlog.`}
   474→          confirmText="Delete"
   475→          cancelText="Cancel"
   476→          variant="danger"
   477→        />
   478→      )}
   479→
   480→      {/* Template Confirmation Dialog */}
   481→      {pendingTemplate && (
   482→        <ConfirmDialog
   483→          isOpen={true}
   484→          onClose={cancelTemplate}
   485→          onConfirm={confirmTemplate}
   486→          title="Apply Template"
   487→          message={`This will replace all current columns with the ${pendingTemplate === 'dev' ? 'Development' : pendingTemplate === 'pm' ? 'Project Management' : 'Marketing'} template. This action cannot be undone.`}
   488→          confirmText="Apply Template"
   489→          cancelText="Cancel"
   490→          variant="warning"
   491→        />
   492→      )}
   493→    </Modal>
   494→  );
   495→};
