   116→              className="p-1 hover:bg-red-100 dark:hover:bg-red-900 rounded text-red-600 transition-colors"
   117→              title="Delete folder"
   118→            >
   119→              🗑️
   120→            </button>
   121→          </div>
   122→        </div>
   123→      </div>
   124→
   125→      {/* Children */}
   126→      {isExpanded && hasChildren && (
   127→        <div className="ml-4">
   128→          {node.children.map((child: any) => (
   129→            <FolderTreeNode
