   518→/**
   519→ * Notes List Component
   520→ */
   521→const NotesList: React.FC = () => {
   522→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   523→  // Get raw notes and store config (stable references)
   524→  const notesObj = useNotesStore((state) => state.notes);
   525→  const sortConfig = useNotesStore((state) => state.sortConfig);
   526→  const filter = useNotesStore((state) => state.filter);
   527→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   528→  const createNote = useNotesStore((state) => state.createNote);
   529→
   530→  // Compute filtered/sorted notes with useMemo
   531→  const notes = useMemo(() => {
   532→    // Filter by folder
   533→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   534→    let filtered = activeFolderId === null
   535→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   536→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   537→
   538→    // Apply filter (archived, pinned, etc.)
   539→    switch (filter) {
   540→      case 'pinned':
   541→        filtered = filtered.filter((note) => note.isPinned);
   542→        break;
   543→      case 'archived':
   544→        filtered = filtered.filter((note) => note.isArchived);
   545→        break;
   546→      case 'unarchived':
   547→        filtered = filtered.filter((note) => !note.isArchived);
   548→        break;
   549→    }
   550→
   551→    // Sort notes
   552→    const sorted = [...filtered].sort((a, b) => {
   553→      let comparison = 0;
   554→      switch (sortConfig.field) {
   555→        case 'title':
   556→          comparison = a.title.localeCompare(b.title);
   557→          break;
   558→        case 'createdAt':
   559→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   560→          break;
   561→        case 'updatedAt':
   562→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   563→          break;
   564→      }
   565→      return sortConfig.order === 'asc' ? comparison : -comparison;
   566→    });
   567→
   568→    // Always pin pinned notes to top
   569→    return sorted.sort((a, b) => {
   570→      if (a.isPinned && !b.isPinned) return -1;
   571→      if (!a.isPinned && b.isPinned) return 1;
   572→      return 0;
   573→    });
   574→  }, [notesObj, activeFolderId, sortConfig, filter]);
   575→
   576→  return (
   577→    <div className="flex-1 overflow-y-auto">
   578→      <div className="bento-card p-4 m-3">
   579→        {/* Notes header */}
   580→        <div className="flex items-center justify-between mb-4">
   581→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   582→            Notes ({notes.length})
   583→          </h3>
   584→          <button
   585→            onClick={() => createNote({ folderId: activeFolderId })}
   586→            className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   587→          >
   588→            + New Note
   589→          </button>
   590→        </div>
   591→
   592→      {/* Notes list */}
   593→      <div className="space-y-2">
   594→        {notes.map((note) => (
   595→          <NoteListItem
   596→            key={note.id}
   597→            note={note}
   598→            isActive={note.id === activeNoteId}
   599→          />
   600→        ))}
   601→      </div>
   602→
   603→      {/* Empty state */}
   604→      {notes.length === 0 && (
   605→        <div className="text-center py-12">
   606→          <div className="text-6xl mb-4">📝</div>
   607→          <h3 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   608→            No notes yet
   609→          </h3>
   610→          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-4">
   611→            Create your first note to get started
   612→          </p>
   613→          <button
   614→            onClick={() => createNote({ folderId: activeFolderId })}
   615→            className="px-4 py-2 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 font-medium"
   616→          >
   617→            Create Note
   618→          </button>
   619→        </div>
   620→      )}
   621→      </div>
   622→    </div>
   623→  );
   624→};
