          >
            <FolderSidebar />
            <NotesList />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Center - Editor */}
      <div className="flex-1 overflow-hidden">
        <div className="h-full overflow-hidden border border-border-light dark:border-border-dark rounded-lg">
          {activeNoteId ? (
            <NotesEditor noteId={activeNoteId} />
          ) : (
            <NotesEditorEmpty />
          )}
        </div>
      </div>

      {/* Right Sidebar - Metadata (Future) */}
      {/* TODO: Add note metadata panel */}
    </div>
    </div>
  );
};

